  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\n// prisma/schema.prisma\n// Define your database models\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Example models\n\n// ─── ENUMS ───────────────────────────────────────────────────\n\nenum TourType {\n  guided // fully guided with a BKT guide\n  self_guided // customer rides alone with route plan\n  rental // just renting the sidecar, no tour\n}\n\nenum Difficulty {\n  easy\n  moderate\n  challenging\n}\n\nenum BookingStatus {\n  pending // just submitted, waiting for admin review\n  rejected // admin rejected the booking\n  paid // customer paid in full\n}\n\nenum RidingExperience {\n  beginner\n  intermediate\n  experienced\n}\n\nenum AdminRole {\n  super_admin // can delete, full access\n  staff // can view and update bookings\n}\n\nenum VehicleType {\n  ural_sidecar\n  dnepr_sidecar\n  solo_bike\n}\n\n// ─── MODELS ──────────────────────────────────────────────────\n\nmodel Tour {\n  id           String      @id @default(cuid()) // unique ID, auto-generated\n  slug         String      @unique // URL-friendly name e.g. \"khangai-classic\"\n  title        String // \"Khangai Classic\"\n  subtitle     String // short tagline\n  description  String      @db.Text // long text, no length limit\n  days         Int // duration\n  price        Float // price per person in USD\n  maxGroupSize Int         @default(8)\n  type         TourType    @default(guided)\n  region       String // \"Khangai\", \"Gobi\", \"Altai\" etc.\n  difficulty   Difficulty  @default(moderate)\n  featured     Boolean     @default(false) // show on homepage\n  published    Boolean     @default(false) // visible to public\n  highlights   String[] // array of highlight strings\n  includes     String[] // what's included\n  excludes     String[] // what's not included\n  images       TourImage[] // relation to images\n  bookings     Booking[] // relation to bookings\n  createdAt    DateTime    @default(now())\n  updatedAt    DateTime    @updatedAt // auto-updates on every save\n\n  @@index([slug])\n  @@index([featured])\n  @@index([published])\n}\n\nmodel TourImage {\n  id        String   @id @default(cuid())\n  tourId    String // which tour this image belongs to\n  tour      Tour     @relation(fields: [tourId], references: [id], onDelete: Cascade)\n  // onDelete: Cascade = if the tour is deleted, all its images are deleted too\n  url       String // Cloudinary URL\n  alt       String? // ? means optional\n  order     Int      @default(0) // for sorting images\n  createdAt DateTime @default(now())\n\n  @@index([tourId])\n}\n\nmodel Rental {\n  id          String      @id @default(cuid())\n  name        String // \"Ural Gear-Up Sidecar\"\n  type        VehicleType\n  description String      @db.Text\n  pricePerDay Float // e.g. 85.00\n  available   Boolean     @default(true) // admin can toggle on/off\n  specs       Json        @default(\"{}\") // flexible key-value specs\n  images      String[] // array of image URLs\n  bookings    Booking[]\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n}\n\nmodel Booking {\n  id     String        @id @default(cuid())\n  status BookingStatus @default(pending)\n\n  // one of these will be set, the other null\n  tourId   String?\n  tour     Tour?   @relation(fields: [tourId], references: [id])\n  rentalId String?\n  rental   Rental? @relation(fields: [rentalId], references: [id])\n\n  startDate        DateTime\n  endDate          DateTime\n  guestName        String\n  guestEmail       String\n  guestPhone       String?\n  nationality      String\n  groupSize        Int              @default(1)\n  ridingExperience RidingExperience @default(beginner)\n  specialRequests  String?          @db.Text\n\n  // payment tracking\n  totalPrice    Float\n  depositAmount Float?\n  depositPaid   Boolean   @default(false)\n  depositPaidAt DateTime?\n\n  // admin use only\n  adminNotes         String?   @db.Text\n  confirmationSentAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([guestEmail])\n  @@index([startDate])\n  @@index([tourId])\n  @@index([rentalId])\n}\n\nmodel Admin {\n  id        String    @id @default(cuid())\n  email     String    @unique\n  name      String\n  password  String // stored as bcrypt hash, never plain text\n  role      AdminRole @default(staff)\n  active    Boolean   @default(true) // deactivate without deleting\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@index([email])\n}\n\nmodel SiteContent {\n  id        String   @id @default(cuid())\n  key       String   @unique // e.g. \"hero_title\", \"about_text\"\n  value     String   @db.Text // the actual content\n  type      String   @default(\"text\") // text | image | richtext\n  updatedAt DateTime @updatedAt\n}\n\nmodel Post {\n  id          String    @id @default(cuid())\n  slug        String    @unique\n  title       String\n  excerpt     String // short preview text\n  body        String    @db.Text // full blog content\n  coverImage  String?\n  published   Boolean   @default(false)\n  publishedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n}\n",
